      { email: 'admin@example.com', name: 'Admin' },
    ]);
    const session = auth();

    await session.attempt({ email: 'admin@example.com', password: 'password123' });
    const user = await session.user();
    expect(user!.name).toBe('Admin');
  });

  it('can inspect cookie state', async () => {
    const { auth, bridge } = await createTestAuth();
    const session = auth();

    await session.attempt({ email: 'alice@example.com', password: 'password123' });

    // The session cookie was set
    expect(bridge.store.has('ideal_session')).toBe(true);

    // Cookie options were applied
    expect(bridge.lastOptions?.httpOnly).toBe(true);
  });
});
```

import { Aside, Steps, Tabs, TabItem } from '@astrojs/starlight/components';

Two-factor authentication (2FA) adds a second verification step after a password login. ideal-auth provides `createTOTP` for time-based one-time passwords (TOTP) and `generateRecoveryCodes` / `verifyRecoveryCode` for backup recovery codes.

This guide covers the complete 2FA lifecycle: setup, login verification, recovery codes, replay protection, and disabling 2FA.

## Setup

```ts
import {
  createTOTP,
  createHash,
  generateRecoveryCodes,
  encrypt,
  decrypt,
} from 'ideal-auth';

const totp = createTOTP(); // defaults: 6 digits, 30s period, window ±1
const hash = createHash();
```

You can customize the TOTP configuration:

```ts
const totp = createTOTP({
  digits: 6,    // number of digits in the code (default: 6)
  period: 30,   // time step in seconds (default: 30)
  window: 1,    // accept codes ±1 time step from current (default: 1)
});
```

## Encryption key

The examples in this guide use `encrypt()` and `decrypt()` to protect TOTP secrets at rest. These functions require a secret key passed as the second argument. Generate one and add it to your environment:

```bash
bunx ideal-auth encryption-key
```

Copy the output into your `.env` file:

```bash title=".env"
ENCRYPTION_KEY="your-generated-key"
```

<Aside type="caution">
  This should be a **separate key** from `IDEAL_AUTH_SECRET`. `IDEAL_AUTH_SECRET` is used for session encryption — `ENCRYPTION_KEY` is for encrypting data you store in your database (like TOTP secrets). Keep both secure and never commit them to version control.
</Aside>

## TOTP setup flow

When a user enables 2FA, you need to generate a secret, show them a QR code, and verify they can produce a valid code before storing the secret.

<Steps>

1. **Generate a secret and QR URI**

   ```ts
   // POST /api/2fa/setup
   export async function setupTwoFactor(req, res) {
     const user = await getAuthenticatedUser(req);

     const secret = totp.generateSecret();
     const qrUri = totp.generateQrUri({
       secret,
       issuer: 'MyApp',
       account: user.email,
     });

     // Store the secret temporarily until the user confirms setup.
     // Encrypt it so it is not stored in plaintext.
     const encryptedSecret = await encrypt(secret, process.env.ENCRYPTION_KEY);

     await db.user.update({
       where: { id: user.id },
       data: { pendingTotpSecret: encryptedSecret },
     });

     return res.json({ qrUri });
   }
   ```

   <Aside type="tip">
     Use a library like [qrcode](https://www.npmjs.com/package/qrcode) to render the `qrUri` as a QR code image on the client. The URI follows the `otpauth://` format that authenticator apps like Google Authenticator and Authy understand.
   </Aside>

2. **User scans the QR code and enters a verification code**

   The client displays the QR code. The user scans it with their authenticator app and submits the 6-digit code.

3. **Verify the code and activate 2FA**

   ```ts
   // POST /api/2fa/confirm
   export async function confirmTwoFactor(req, res) {
     const user = await getAuthenticatedUser(req);
     const { code } = req.body;

     if (!user.pendingTotpSecret) {
       return res.status(400).json({ error: 'No pending 2FA setup' });
     }

     // Decrypt the pending secret
     const secret = await decrypt(
       user.pendingTotpSecret,
       process.env.ENCRYPTION_KEY,
     );

     // Verify the code from the authenticator app
     if (!totp.verify(code, secret)) {
       return res.status(400).json({ error: 'Invalid code' });
     }

     // Encrypt the confirmed secret for permanent storage
     const encryptedSecret = await encrypt(secret, process.env.ENCRYPTION_KEY);

     // Generate recovery codes
     const { codes, hashed } = await generateRecoveryCodes(hash);

     await db.user.update({
       where: { id: user.id },
       data: {
         totpSecret: encryptedSecret,
         pendingTotpSecret: null,
         recoveryCodeHashes: hashed,
         twoFactorEnabled: true,
       },
     });

     // Show recovery codes to the user ONCE
     return res.json({
       message: '2FA enabled',
       recoveryCodes: codes,
     });
   }
   ```

</Steps>

<Aside type="caution">
  Recovery codes must be shown to the user exactly once during setup. Store only the hashed versions in your database. If a user loses their codes, they will need to generate new ones.
</Aside>

## TOTP login verification

After a user logs in with their password, you need to check whether they have 2FA enabled. If they do, **do not complete the session** until 2FA is verified. The pattern uses a short-lived pending cookie to track the intermediate state.

### Step 1: Password login sets a pending cookie

```ts
import { createAuth, createHash, createTokenVerifier } from 'ideal-auth';

const hash = createHash();
const auth = createAuth({
  secret: process.env.SESSION_SECRET,
  cookie: cookieBridge,
  hash,
  resolveUser: (id) => db.user.findUnique({ where: { id } }),
  resolveUserByCredentials: (creds) =>
    db.user.findUnique({ where: { email: creds.email } }),
});

// Token verifier for the 2FA pending state (short-lived)
const pendingVerifier = createTokenVerifier({
  secret: process.env.SESSION_SECRET,
  expiryMs: 5 * 60 * 1000, // 5 minutes
});

// POST /api/login
export async function login(req, res) {
  const { email, password, remember } = req.body;
  const session = auth();

  // Find the user and verify password manually
  // (don't use attempt() yet because we might need to gate on 2FA)
  const user = await db.user.findUnique({ where: { email } });
  if (!user) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const valid = await hash.verify(password, user.password);
  if (!valid) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  // If 2FA is enabled, set a pending cookie instead of logging in
  if (user.twoFactorEnabled) {
    const pendingToken = pendingVerifier.createToken(String(user.id));

    await cookieBridge.set('2fa_pending', pendingToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      path: '/',
      maxAge: 300, // 5 minutes
    });

    return res.json({ requiresTwoFactor: true });
  }

  // No 2FA — log in directly
  await session.login(user, { remember });
  return res.json({ success: true });
}
```

### Step 2: Verify the TOTP code and complete login

```ts
// POST /api/2fa/verify
export async function verifyTwoFactor(req, res) {
  const { code, remember } = req.body;

  // Read the pending cookie
  const pendingToken = await cookieBridge.get('2fa_pending');
  if (!pendingToken) {
    return res.status(401).json({ error: 'No pending 2FA session' });
  }

  // Verify the pending token
  const result = pendingVerifier.verifyToken(pendingToken);
  if (!result) {
    return res.status(401).json({ error: '2FA session expired' });
  }

  const user = await db.user.findUnique({ where: { id: result.userId } });
  if (!user || !user.twoFactorEnabled) {
    return res.status(401).json({ error: 'Invalid session' });
  }

  // Decrypt the TOTP secret and verify the code
  const secret = await decrypt(user.totpSecret, process.env.ENCRYPTION_KEY);

  if (!totp.verify(code, secret)) {
    return res.status(400).json({ error: 'Invalid 2FA code' });
  }

  // Delete the pending cookie and create a real session
  await cookieBridge.delete('2fa_pending');

  const session = auth();
  await session.login(user, { remember });

  return res.json({ success: true });
}
```

### Step 3: Middleware to redirect pending users

In frameworks with middleware (Next.js, SvelteKit), redirect users who have a pending 2FA cookie to the verification page:

<Tabs>
  <TabItem label="Next.js">
    ```ts
    // middleware.ts
    import { NextResponse } from 'next/server';
    import type { NextRequest } from 'next/server';

    export function middleware(request: NextRequest) {
      const hasPending = request.cookies.has('2fa_pending');
      const isOnTwoFactorPage = request.nextUrl.pathname === '/2fa';
      const isApiRoute = request.nextUrl.pathname.startsWith('/api/');

      // User has a pending 2FA cookie but isn't on the 2FA page
      if (hasPending && !isOnTwoFactorPage && !isApiRoute) {
        return NextResponse.redirect(new URL('/2fa', request.url));
      }

      // User is on the 2FA page without a pending cookie
      if (!hasPending && isOnTwoFactorPage) {
        return NextResponse.redirect(new URL('/login', request.url));
      }

      return NextResponse.next();
    }

    export const config = {
      matcher: ['/((?!_next/static|_next/image|favicon.ico).*)'],
    };
    ```
  </TabItem>
  <TabItem label="SvelteKit">
    ```ts
    // src/hooks.server.ts
    import { redirect } from '@sveltejs/kit';
    import type { Handle } from '@sveltejs/kit';

    export const handle: Handle = async ({ event, resolve }) => {
      const hasPending = event.cookies.get('2fa_pending');
      const isOnTwoFactorPage = event.url.pathname === '/2fa';
      const isApiRoute = event.url.pathname.startsWith('/api/');

      if (hasPending && !isOnTwoFactorPage && !isApiRoute) {
        throw redirect(302, '/2fa');
      }

      if (!hasPending && isOnTwoFactorPage) {
        throw redirect(302, '/login');
      }

      return resolve(event);
    };
    ```
  </TabItem>
</Tabs>

## Recovery codes

Recovery codes allow users to log in when they lose access to their authenticator app. ideal-auth generates 8 codes by default, each formatted as `xxxxxxxx-xxxxxxxx`.

### Generating recovery codes

Recovery codes are generated during 2FA setup (shown above) or when a user regenerates them:

```ts
import { generateRecoveryCodes, createHash } from 'ideal-auth';

const hash = createHash();
const { codes, hashed } = await generateRecoveryCodes(hash);

// codes:  ['a1b2c3d4-e5f6a7b8', '...', ...]  — show to user
// hashed: ['$2a$12$...', '$2a$12$...', ...]    — store in database
```

You can pass a custom count:

```ts
const { codes, hashed } = await generateRecoveryCodes(hash, 12);
```

### Verifying a recovery code

```ts
import { verifyRecoveryCode } from 'ideal-auth';

// POST /api/2fa/recover
export async function recoverWithCode(req, res) {
  const { code, remember } = req.body;

  // Read and verify the pending cookie (same as TOTP verify)
  const pendingToken = await cookieBridge.get('2fa_pending');
  if (!pendingToken) {
    return res.status(401).json({ error: 'No pending 2FA session' });
  }

  const result = pendingVerifier.verifyToken(pendingToken);
  if (!result) {
    return res.status(401).json({ error: '2FA session expired' });
  }

  const user = await db.user.findUnique({ where: { id: result.userId } });
  if (!user) {
    return res.status(401).json({ error: 'Invalid session' });
  }

  // Verify the recovery code
  const { valid, remaining } = await verifyRecoveryCode(
    code,
    user.recoveryCodeHashes,
    hash,
  );

  if (!valid) {
    return res.status(400).json({ error: 'Invalid recovery code' });
  }

  // Update the stored hashes — the used code is removed from `remaining`
  await db.user.update({
    where: { id: user.id },
    data: { recoveryCodeHashes: remaining },
  });

  // Delete the pending cookie and create a real session
  await cookieBridge.delete('2fa_pending');

  const session = auth();
  await session.login(user, { remember });

  return res.json({
    success: true,
    remainingCodes: remaining.length,
  });
}
```

<Aside type="caution">
  Always update the stored hashes to `remaining` after a successful verification. The `remaining` array is the original array with the used code removed. If you skip this step, the same recovery code can be used multiple times.
</Aside>

### Regenerating recovery codes

Users should be able to regenerate their recovery codes. This invalidates all previous codes:

```ts
// POST /api/2fa/regenerate-codes
export async function regenerateCodes(req, res) {
  const user = await getAuthenticatedUser(req);

  if (!user.twoFactorEnabled) {
    return res.status(400).json({ error: '2FA is not enabled' });
  }

  const { codes, hashed } = await generateRecoveryCodes(hash);

  await db.user.update({
    where: { id: user.id },
    data: { recoveryCodeHashes: hashed },
  });

  // Show new codes to the user
  return res.json({ recoveryCodes: codes });
}
```

## Replay protection

TOTP codes are valid for the current time step plus any steps within the configured `window`. With the default settings (30-second period, window of 1), a code is valid for up to 90 seconds (the previous, current, and next time steps). This means a code could be reused within that window.

To prevent replay attacks, store the last used time step for each user and reject codes at or before that step.

### Implementation

```ts
function getCurrentTimeStep(period: number = 30): number {
  return Math.floor(Date.now() / 1000 / period);
}

// POST /api/2fa/verify (enhanced with replay protection)
export async function verifyTwoFactorWithReplayProtection(req, res) {
  const { code, remember } = req.body;

  const pendingToken = await cookieBridge.get('2fa_pending');
  if (!pendingToken) {
    return res.status(401).json({ error: 'No pending 2FA session' });
  }

  const result = pendingVerifier.verifyToken(pendingToken);
  if (!result) {
    return res.status(401).json({ error: '2FA session expired' });
  }

  const user = await db.user.findUnique({ where: { id: result.userId } });
  if (!user || !user.twoFactorEnabled) {
    return res.status(401).json({ error: 'Invalid session' });
  }

  const secret = await decrypt(user.totpSecret, process.env.ENCRYPTION_KEY);

  // Verify the TOTP code
  if (!totp.verify(code, secret)) {
    return res.status(400).json({ error: 'Invalid 2FA code' });
  }

  // Check for replay: reject if the current time step has already been used
  const currentStep = getCurrentTimeStep();
  if (user.lastTotpStep && currentStep <= user.lastTotpStep) {
    return res.status(400).json({ error: 'Code already used' });
  }

  // Record the time step to prevent replay
  await db.user.update({
    where: { id: user.id },
    data: { lastTotpStep: currentStep },
  });

  // Delete the pending cookie and create a real session
  await cookieBridge.delete('2fa_pending');

  const session = auth();
  await session.login(user, { remember });

  return res.json({ success: true });
}
```

### Database schema addition

Add a column to track the last used time step:

```sql
ALTER TABLE users ADD COLUMN last_totp_step BIGINT;
```

<Aside>
  Replay protection is most important in scenarios where an attacker might intercept a valid TOTP code (e.g., shoulder surfing, compromised clipboard). For most applications, the short validity window of TOTP codes already provides reasonable protection, but adding replay protection is a best practice.
</Aside>

## Disabling 2FA

Always require the user's current password before disabling 2FA. This prevents an attacker who has access to an active session from removing the second factor.

```ts
// POST /api/2fa/disable
export async function disableTwoFactor(req, res) {
  const user = await getAuthenticatedUser(req);
  const { password } = req.body;

  if (!user.twoFactorEnabled) {
    return res.status(400).json({ error: '2FA is not enabled' });
  }

  // Verify current password
  const valid = await hash.verify(password, user.password);
  if (!valid) {
    return res.status(401).json({ error: 'Invalid password' });
  }

  // Clear all 2FA data
  await db.user.update({
    where: { id: user.id },
    data: {
      twoFactorEnabled: false,
      totpSecret: null,
      pendingTotpSecret: null,
      recoveryCodeHashes: null,
      lastTotpStep: null,
    },
  });

  return res.json({ message: '2FA disabled' });
}
```

## Complete database schema

Here is a reference schema with all the columns needed for 2FA:

```sql
CREATE TABLE users (
  id            TEXT PRIMARY KEY,
  email         TEXT UNIQUE NOT NULL,
  password      TEXT NOT NULL,

  -- 2FA fields
  two_factor_enabled    BOOLEAN DEFAULT FALSE,
  totp_secret           TEXT,           -- encrypted with encrypt()
  pending_totp_secret   TEXT,           -- encrypted, temporary during setup
  recovery_code_hashes  TEXT[],         -- array of bcrypt hashes
  last_totp_step        BIGINT          -- replay protection
);
```

## Security checklist

- Always encrypt the TOTP secret at rest using `encrypt()` from ideal-auth
- Never log or expose the TOTP secret after initial setup
- Show recovery codes exactly once; store only the bcrypt hashes
- Use a short-lived pending cookie (5 minutes or less) for the 2FA intermediate state
- Implement replay protection by tracking the last used time step
- Require password verification before disabling 2FA
- Rate limit 2FA verification attempts to prevent brute force
- Use the `2fa_pending` cookie only over HTTPS in production

import { Aside, Tabs, TabItem } from '@astrojs/starlight/components';

ideal-auth does **not** handle CSRF protection. This is by design — CSRF mitigation is a framework-level concern, and every major framework has its own mechanism. This guide explains the threat and walks through prevention strategies for each supported framework.

---

## What is CSRF?

Cross-Site Request Forgery (CSRF) is an attack where a malicious website tricks a user's browser into making an authenticated request to your application. Because the browser automatically attaches cookies (including session cookies) to every request to your domain, the attacker can perform actions as the logged-in user without their knowledge.

**Example attack:**

1. A user is logged into your application at `app.example.com`
2. The user visits `evil.example.com`, which contains a hidden form:
   ```html
   <form action="https://app.example.com/api/transfer" method="POST">
     <input type="hidden" name="to" value="attacker" />
     <input type="hidden" name="amount" value="1000" />
   </form>
   <script>document.forms[0].submit();</script>
   ```
3. The browser submits the form with the user's session cookie attached
4. Your server processes the transfer as if the user initiated it

This is why CSRF protection matters for any application that uses cookie-based authentication — which includes ideal-auth.

---

## Why ideal-auth does not handle CSRF

CSRF protection requires intercepting incoming requests before they reach your application logic. This is inherently framework-specific:

- Next.js Server Actions have built-in protection
- SvelteKit form actions have built-in protection
- Express requires middleware
- Hono has a built-in middleware

Implementing CSRF at the auth library level would mean coupling to a specific framework's request/response model, which contradicts ideal-auth's framework-agnostic design. Instead, ideal-auth provides the **SameSite cookie attribute** (default: `lax`) as a foundational defense layer, and you add framework-specific CSRF protection on top.

---

## Framework-specific strategies

<Tabs>
  <TabItem label="Next.js">
    **Server Actions** have built-in CSRF protection. Next.js automatically validates the `Origin` header on all Server Action requests and rejects cross-origin submissions. No configuration is needed.

    **API Route Handlers** (`app/api/*/route.ts`) do **not** have automatic CSRF protection. If you accept state-changing requests via API routes, validate the `Origin` header manually:

    ```ts title="app/api/example/route.ts"
    import { headers } from 'next/headers';
    import { NextResponse } from 'next/server';

    export async function POST(request: Request) {
      const headerStore = await headers();
      const origin = headerStore.get('origin');
      const host = headerStore.get('host');

      if (!origin || new URL(origin).host !== host) {
        return NextResponse.json(
          { error: 'Invalid origin' },
          { status: 403 },
        );
      }

      // ... handle the request
    }
    ```

    <Aside type="tip">
      If all your state-changing operations use Server Actions (the recommended pattern), you already have CSRF protection with zero extra code.
    </Aside>
  </TabItem>

  <TabItem label="SvelteKit">
    **Form actions** have built-in CSRF protection. SvelteKit validates the `Origin` header against the server's host on all form action submissions and returns a `403` for mismatches.

    This is enabled by default. You can verify it has not been disabled in your `svelte.config.js`:

    ```js title="svelte.config.js"
    const config = {
      kit: {
        // csrf.checkOrigin defaults to true — do not set it to false
        csrf: {
          checkOrigin: true,
        },
      },
    };
    ```

    **Custom API endpoints** (`+server.ts`) do not receive automatic CSRF protection. Apply the same Origin header check:

    ```ts title="src/routes/api/example/+server.ts"
    import { error, json } from '@sveltejs/kit';
    import type { RequestHandler } from './$types';

    export const POST: RequestHandler = async ({ request, url }) => {
      const origin = request.headers.get('origin');
      if (!origin || new URL(origin).host !== url.host) {
        throw error(403, 'Invalid origin');
      }

      // ... handle the request
      return json({ ok: true });
    };
    ```
  </TabItem>

  <TabItem label="Nuxt">
    Nuxt does not include built-in CSRF protection. Use the [nuxt-csrf](https://github.com/morgenstern-ui/nuxt-csurf) module or implement Origin header validation in server middleware:

    **Option 1: nuxt-csrf module**

    ```bash
    npx nuxi module add nuxt-csurf
    ```

    The module automatically generates a CSRF token and validates it on form submissions.

    **Option 2: Manual Origin check**

    ```ts title="server/middleware/csrf.ts"
    export default defineEventHandler((event) => {
      if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(event.method)) {
        const origin = getHeader(event, 'origin');
        const host = getHeader(event, 'host');

        if (!origin || !host || new URL(origin).host !== host) {
          throw createError({
            statusCode: 403,
            message: 'Invalid origin',
          });
        }
      }
    });
    ```
  </TabItem>

  <TabItem label="TanStack Start">
    TanStack Start does not include built-in CSRF protection. Validate the `Origin` header in your server functions:

    ```ts title="app/lib/csrf.ts"
    export function validateOrigin(request: Request): void {
      const origin = request.headers.get('origin');
      const host = request.headers.get('host');

      if (!origin || !host || new URL(origin).host !== host) {
        throw new Error('CSRF validation failed');
      }
    }
    ```

    Call this at the start of any server function that performs a state-changing operation:

    ```ts title="app/routes/api/example.ts"
    import { validateOrigin } from '../lib/csrf';

    export const serverFn = createServerFn('POST', async (data, ctx) => {
      validateOrigin(ctx.request);
      // ... handle the request
    });
    ```
  </TabItem>

  <TabItem label="Express">
    Use the double-submit cookie pattern or a dedicated CSRF middleware. The popular `csrf-csrf` package implements the double-submit pattern:

    ```bash
    npm install csrf-csrf
    ```

    ```ts title="src/middleware/csrf.ts"
    import { doubleCsrf } from 'csrf-csrf';

    const { doubleCsrfProtection, generateToken } = doubleCsrf({
      getSecret: () => process.env.CSRF_SECRET!,
      cookieName: '__csrf',
      cookieOptions: {
        httpOnly: true,
        sameSite: 'lax',
        secure: process.env.NODE_ENV === 'production',
        path: '/',
      },
      getTokenFromRequest: (req) => req.headers['x-csrf-token'] as string,
    });

    export { doubleCsrfProtection, generateToken };
    ```

    ```ts title="src/app.ts"
    import express from 'express';
    import { doubleCsrfProtection } from './middleware/csrf';

    const app = express();

    // Apply CSRF protection to all state-changing routes
    app.use(doubleCsrfProtection);
    ```
  </TabItem>

  <TabItem label="Hono">
    Hono has a built-in `csrf()` middleware that validates the `Origin` header:

    ```ts title="src/index.ts"
    import { Hono } from 'hono';
    import { csrf } from 'hono/csrf';

    const app = new Hono();

    app.use(csrf());
    ```

    By default, this checks the `Origin` header against the request's host. You can specify allowed origins:

    ```ts
    app.use(csrf({
      origin: ['https://app.example.com', 'https://staging.example.com'],
    }));
    ```
  </TabItem>

  <TabItem label="Elysia">
    Elysia does not include built-in CSRF protection. Validate the `Origin` header in a global `onBeforeHandle` hook:

    ```ts title="src/index.ts"
    import { Elysia } from 'elysia';

    const app = new Elysia()
      .onBeforeHandle((ctx) => {
        if (ctx.request.method === 'GET' || ctx.request.method === 'HEAD') {
          return;
        }

        const origin = ctx.request.headers.get('origin');
        const host = ctx.request.headers.get('host');

        if (!origin || !host || new URL(origin).host !== host) {
          ctx.set.status = 403;
          throw new Error('CSRF validation failed');
        }
      });
    ```
  </TabItem>
</Tabs>

---

## The double-submit cookie pattern

If your framework does not provide built-in CSRF protection, the double-submit cookie pattern is a reliable framework-agnostic fallback. Here is how it works:

1. **On page load**, the server sets a random CSRF token in a cookie (`sameSite: 'strict'`, **not** `httpOnly` — JavaScript needs to read it)
2. **On form submission**, JavaScript reads the token from the cookie and includes it as a request header (e.g., `X-CSRF-Token`)
3. **On the server**, the middleware compares the token in the header to the token in the cookie. If they match, the request is legitimate

This works because:
- A cross-origin attacker can cause the browser to **send** cookies, but cannot **read** cookies belonging to your domain
- The attacker cannot set the `X-CSRF-Token` header because they cannot read the cookie value
- `SameSite: strict` on the CSRF cookie prevents the cookie from being sent in cross-origin requests at all

```ts title="Example: manual double-submit implementation"
import { randomBytes } from 'node:crypto';

// Generate and set the CSRF token cookie
function setCsrfToken(setCookie: (name: string, value: string, options: any) => void): string {
  const token = randomBytes(32).toString('hex');
  setCookie('csrf_token', token, {
    httpOnly: false,    // JavaScript must read this
    sameSite: 'strict',
    secure: process.env.NODE_ENV === 'production',
    path: '/',
  });
  return token;
}

// Validate the CSRF token on incoming requests
function validateCsrfToken(
  cookieToken: string | undefined,
  headerToken: string | undefined,
): boolean {
  if (!cookieToken || !headerToken) return false;
  // Use timing-safe comparison
  return cookieToken.length === headerToken.length &&
    require('node:crypto').timingSafeEqual(
      Buffer.from(cookieToken),
      Buffer.from(headerToken),
    );
}
```

---

## SameSite cookies as a defense layer

ideal-auth defaults to `sameSite: 'lax'` on session cookies. This provides baseline CSRF protection by itself:

| SameSite value | Behavior |
|----------------|----------|
| `strict` | Cookie is never sent in cross-origin requests. Maximum protection, but breaks legitimate navigation (e.g., clicking a link from an email) |
| `lax` (default) | Cookie is sent for top-level navigations (GET) but **not** for cross-origin form submissions (POST). Protects against the most common CSRF vectors |
| `none` | Cookie is always sent. Requires `secure: true`. No CSRF protection from this attribute |

`SameSite: lax` blocks the classic CSRF attack (cross-origin POST) while still allowing users to follow links to your app without losing their session. For most applications, this is the correct default.

<Aside type="caution">
  `SameSite: lax` does not protect against CSRF in GET requests. Never perform state-changing operations in response to GET requests. All mutations should use POST, PUT, PATCH, or DELETE.
</Aside>

---

## Summary

| Framework | Forms/Actions | API Routes |
|-----------|--------------|------------|
| Next.js | Built-in (Server Actions) | Manual Origin check |
| SvelteKit | Built-in (form actions) | Manual Origin check |
| Nuxt | nuxt-csrf module or manual | nuxt-csrf module or manual |
| TanStack Start | Manual Origin check | Manual Origin check |
| Express | csrf-csrf or double-submit | csrf-csrf or double-submit |
| Hono | Built-in csrf() middleware | Built-in csrf() middleware |
| Elysia | Manual Origin check | Manual Origin check |

import { Aside, Steps } from '@astrojs/starlight/components';

This guide walks through migrating from [Better Auth](https://www.better-auth.com) to ideal-auth. Better Auth is a full-featured authentication framework that manages your database schema, sessions, and plugins. ideal-auth takes the opposite approach — it provides primitives and lets you manage everything else.

---

## Why migrate?

**Better Auth manages your schema.** It creates and manages `users`, `sessions`, and `accounts` tables (plus more for plugins). If you need to change the schema, you work within Better Auth's constraints. ideal-auth does not touch your database — you write the queries, you own the schema entirely.

**Better Auth uses server-side sessions.** Every session check requires a database query to validate the session ID. ideal-auth uses encrypted cookies (iron-session), so session validation is a cryptographic operation with no database round-trip. This reduces latency and database load, especially at scale.

**Simpler dependency tree.** Better Auth includes adapters, plugins, OAuth handling, and a client-side SDK. ideal-auth has two runtime dependencies (`iron-session` and `bcryptjs`) and zero framework dependencies. Less code means less to audit and fewer potential vulnerabilities.

**No plugin architecture.** Better Auth's plugin system (2FA, magic link, anonymous auth, etc.) adds features through a plugin API with lifecycle hooks. ideal-auth provides TOTP, recovery codes, token verification, and rate limiting as standalone functions. You compose them yourself — no plugin lifecycle, no implicit state changes.

---

## Key differences

| Concept | Better Auth | ideal-auth |
|---------|-------------|------------|
| Session storage | Database (sessions table) | Encrypted cookie (iron-session) |
| Schema management | Managed by Better Auth | You manage your own schema |
| Database access | Built-in adapters (Prisma, Drizzle, Kysely, etc.) | You write the queries (`resolveUser`, `resolveUserByCredentials`) |
| Session check | Database lookup per request | Cryptographic verification (no DB query) |
| Login | `signIn.email({ email, password })` | `session.attempt({ email, password })` |
| Logout | `signOut()` | `session.logout()` |
| Get session | `useSession()` (client) or `auth.api.getSession()` | `session.user()` (server-side only) |
| 2FA | Plugin (`twoFactor()`) | Built-in (`createTOTP`, `generateRecoveryCodes`) |
| OAuth | Built-in with `socialProviders` | Not included — use [Arctic](https://arcticjs.dev) |
| Rate limiting | Not built-in | Built-in (`createRateLimiter`) |
| Token verification | Not built-in (sessions used for everything) | Built-in (`createTokenVerifier`) for reset/verify flows |
| Client SDK | `createAuthClient()` | None — server-side only, pass data via props |

---

## Migration steps

<Steps>

1. ### Map your existing schema

   Better Auth typically creates these tables:

   - `users` — id, name, email, emailVerified, image, createdAt, updatedAt
   - `sessions` — id, userId, token, expiresAt, ipAddress, userAgent, createdAt, updatedAt
   - `accounts` — id, userId, accountId, providerId, accessToken, refreshToken, etc.

   With ideal-auth, you keep the `users` table (adding a `password` column if you do not have one) and drop the `sessions` and `accounts` tables (sessions are now cookie-based). If you use OAuth, keep the `accounts` table for linking OAuth providers to users.

   ```sql
   -- Ensure your users table has a password column
   ALTER TABLE users ADD COLUMN IF NOT EXISTS password VARCHAR(255);

   -- After migration is complete, you can drop these:
   -- DROP TABLE sessions;
   -- DROP TABLE accounts; -- only if you no longer need OAuth
   ```

   <Aside type="caution">
     Do not drop the `sessions` table until all active Better Auth sessions have expired or you have fully migrated. Dropping it while Better Auth is still running will log out all users immediately.
   </Aside>

2. ### Install ideal-auth

   ```bash
   bun add ideal-auth
   ```

   Add the session secret to your environment:

   ```bash title=".env"
   IDEAL_AUTH_SECRET="your-32-character-or-longer-secret"
   ```

3. ### Create the auth configuration

   ```ts title="lib/auth.ts"
   import { createAuth, createHash } from 'ideal-auth';

   type User = {
     id: string;
     email: string;
     name: string;
     password: string;
   };

   export const hash = createHash({ rounds: 12 });

   export const auth = createAuth<User>({
     secret: process.env.IDEAL_AUTH_SECRET!,
     cookie: createCookieBridge(), // see framework guides for your framework
     hash,

     async resolveUser(id) {
       // This replaces Better Auth's adapter.findUserById
       return db.user.findUnique({ where: { id } });
     },

     async resolveUserByCredentials(credentials) {
       // This replaces Better Auth's credential verification
       return db.user.findUnique({
         where: { email: credentials.email },
       });
     },
   });
   ```

   <Aside type="tip">
     See the [Framework Guides](/ideal-auth/frameworks/nextjs/) for complete cookie bridge implementations for your framework.
   </Aside>

4. ### Replace signIn.email with session.attempt

   **Before (Better Auth):**
   ```ts
   // Client-side
   import { authClient } from '@/lib/auth-client';

   const { data, error } = await authClient.signIn.email({
     email: 'user@example.com',
     password: 'password123',
   });
   ```

   **After (ideal-auth):**
   ```ts title="app/actions/login.ts"
   'use server';

   import { redirect } from 'next/navigation';
   import { auth } from '@/lib/auth';

   export async function loginAction(_prev: unknown, formData: FormData) {
     const email = formData.get('email') as string;
     const password = formData.get('password') as string;

     if (!email || !password) {
       return { error: 'Email and password are required.' };
     }

     const session = auth();
     const success = await session.attempt({ email, password });

     if (!success) {
       return { error: 'Invalid email or password.' };
     }

     redirect('/dashboard');
   }
   ```

   <Aside>
     Better Auth's `signIn.email` is a client-to-server API call. ideal-auth's `session.attempt` runs server-side (in a Server Action, API route, or server function). This means no client SDK and no client-side auth state — the session is managed entirely through cookies.
   </Aside>

5. ### Replace signOut with session.logout

   **Before (Better Auth):**
   ```ts
   await authClient.signOut();
   ```

   **After (ideal-auth):**
   ```ts title="app/actions/logout.ts"
   'use server';

   import { redirect } from 'next/navigation';
   import { auth } from '@/lib/auth';

   export async function logoutAction() {
     const session = auth();
     await session.logout();
     redirect('/login');
   }
   ```

6. ### Replace useSession with server-side session access

   **Before (Better Auth):**
   ```tsx
   // Client component
   import { authClient } from '@/lib/auth-client';

   function Dashboard() {
     const { data: session, isPending } = authClient.useSession();

     if (isPending) return <p>Loading...</p>;
     if (!session) redirect('/login');

     return <p>Welcome, {session.user.name}</p>;
   }
   ```

   **After (ideal-auth):**

   ideal-auth does not provide a client-side session hook. Fetch the user server-side and pass data as props:

   ```tsx title="app/dashboard/page.tsx"
   import { auth } from '@/lib/auth';
   import { redirect } from 'next/navigation';
   import { DashboardClient } from './dashboard-client';

   export default async function DashboardPage() {
     const session = auth();
     const user = await session.user();

     if (!user) {
       redirect('/login');
     }

     return (
       <DashboardClient
         user={{ id: user.id, name: user.name, email: user.email }}
       />
     );
   }
   ```

   ```tsx title="app/dashboard/dashboard-client.tsx"
   'use client';

   type Props = {
     user: { id: string; name: string; email: string };
   };

   export function DashboardClient({ user }: Props) {
     return <p>Welcome, {user.name}</p>;
   }
   ```

7. ### Migrate 2FA

   If you are using Better Auth's `twoFactor()` plugin, migrate to ideal-auth's built-in TOTP:

   **Before (Better Auth):**
   ```ts
   // Server config
   import { twoFactor } from 'better-auth/plugins';

   export const auth = betterAuth({
     plugins: [twoFactor()],
   });

   // Client
   const { data } = await authClient.twoFactor.enable({ password });
   await authClient.twoFactor.verifyTotp({ code });
   ```

   **After (ideal-auth):**
   ```ts title="lib/totp.ts"
   import { createTOTP, generateRecoveryCodes, verifyRecoveryCode } from 'ideal-auth';
   import { hash } from './auth';

   export const totp = createTOTP({
     digits: 6,
     period: 30,
     window: 1,
   });
   ```

   ```ts title="app/actions/2fa-setup.ts"
   'use server';

   import { totp } from '@/lib/totp';
   import { hash } from '@/lib/auth';
   import { encrypt } from 'ideal-auth';
   import { generateRecoveryCodes } from 'ideal-auth';
   import { db } from '@/lib/db';

   export async function enable2FA(userId: string) {
     // Generate TOTP secret
     const secret = totp.generateSecret();

     // Generate recovery codes
     const { codes, hashed } = await generateRecoveryCodes(hash);

     // Generate QR URI for authenticator app
     const user = await db.user.findUnique({ where: { id: userId } });
     const qrUri = totp.generateQrUri({
       secret,
       issuer: 'YourApp',
       account: user!.email,
     });

     // Store encrypted secret and hashed recovery codes
     const encryptedSecret = await encrypt(secret, process.env.TOTP_KEY!);
     await db.user.update({
       where: { id: userId },
       data: {
         totpSecret: encryptedSecret,
         recoveryCodes: hashed,
         twoFactorEnabled: true,
       },
     });

     // Return codes to show the user (one time only)
     return { qrUri, recoveryCodes: codes };
   }
   ```

   ```ts title="app/actions/2fa-verify.ts"
   'use server';

   import { totp } from '@/lib/totp';
   import { decrypt } from 'ideal-auth';
   import { db } from '@/lib/db';

   export async function verify2FA(userId: string, code: string) {
     const user = await db.user.findUnique({ where: { id: userId } });
     if (!user?.totpSecret) return { error: '2FA is not enabled.' };

     const secret = await decrypt(user.totpSecret, process.env.TOTP_KEY!);
     const isValid = totp.verify(code, secret);

     if (!isValid) {
       return { error: 'Invalid code.' };
     }

     return { success: true };
   }
   ```

   Better Auth stores 2FA state in the `accounts` table via its plugin system. With ideal-auth, you add `totpSecret`, `recoveryCodes`, and `twoFactorEnabled` columns to your `users` table (or a separate table) and manage the state yourself.

8. ### Remove Better Auth

   Once all flows are migrated and tested:

   ```bash
   bun remove better-auth
   ```

   Delete:
   - `lib/auth.ts` (Better Auth server config) — replace with your ideal-auth config
   - `lib/auth-client.ts` (Better Auth client) — no longer needed
   - `app/api/auth/[...all]/route.ts` (Better Auth API route) — no longer needed
   - Better Auth migration files if you used `npx @better-auth/cli migrate`

   After confirming all users can log in with the new system:

   ```sql
   -- Drop Better Auth's session table (sessions are now cookie-based)
   DROP TABLE IF EXISTS sessions;

   -- Drop accounts table only if you no longer need OAuth provider linking
   -- DROP TABLE IF EXISTS accounts;
   ```

</Steps>

---

## Schema migration

Better Auth manages specific tables. Here is what to keep and what to drop:

| Better Auth table | Action | Notes |
|-------------------|--------|-------|
| `users` | **Keep** | Add `password` column if missing. Add `totpSecret`, `recoveryCodes`, `twoFactorEnabled` if migrating 2FA. |
| `sessions` | **Drop** (after migration) | ideal-auth uses encrypted cookies, not database sessions |
| `accounts` | **Keep if using OAuth** | Stores OAuth provider links. Keep if you plan to use Arctic for OAuth. |
| `verifications` | **Drop** (after migration) | Replace with `createTokenVerifier` for email verification and password reset flows |

<Aside>
  If Better Auth hashed passwords using bcrypt (the default), ideal-auth can verify them directly — bcrypt hashes are compatible. No rehashing is needed for existing users.
</Aside>

---

## Session storage comparison

This is the most significant architectural difference:

**Better Auth** stores sessions in your database. Every `auth.api.getSession()` call queries the `sessions` table. This means:
- Session invalidation is easy (delete the row)
- Every page load hits the database
- Horizontal scaling requires a shared database or session store

**ideal-auth** stores sessions in encrypted cookies. Every `session.user()` call decrypts the cookie (no database query for session validation — only for user resolution via `resolveUser`). This means:
- No session table, no session garbage collection
- Session validation is CPU-only (cryptographic decryption)
- Horizontal scaling requires no shared state
- Session invalidation requires patterns described in the [Session Invalidation](/ideal-auth/security/session-invalidation/) guide

For most applications, the encrypted cookie approach is simpler and faster. If you need server-side session revocation (e.g., "logout everywhere"), see the [Session Invalidation](/ideal-auth/security/session-invalidation/) guide for practical patterns.

---

## Handling OAuth users

If you used Better Auth's `socialProviders` for OAuth login, you have users in the `accounts` table linked to OAuth providers. These users may not have a password.

**Recommended approach:** Use [Arctic](https://arcticjs.dev) for OAuth. After verifying the OAuth token, look up the user via their `accounts` record and call `session.login(user)`:

```ts
import { GitHub } from 'arctic';
import { auth } from '@/lib/auth';

const github = new GitHub(
  process.env.GITHUB_CLIENT_ID!,
  process.env.GITHUB_CLIENT_SECRET!,
  null,
);

export async function handleGitHubCallback(code: string) {
  const tokens = await github.validateAuthorizationCode(code);
  const githubUser = await fetchGitHubUser(tokens.accessToken());

  // Find user via accounts table (your existing Better Auth data)
  const account = await db.account.findFirst({
    where: {
      providerId: 'github',
      accountId: String(githubUser.id),
    },
    include: { user: true },
  });

  if (!account) {
    // New OAuth user — create user and account
    const user = await db.user.create({
      data: { email: githubUser.email, name: githubUser.name },
    });
    await db.account.create({
      data: {
        userId: user.id,
        providerId: 'github',
        accountId: String(githubUser.id),
      },
    });
    const session = auth();
    await session.login(user);
    return;
  }

  // Existing user — log them in
  const session = auth();
  await session.login(account.user);
}
```

This lets OAuth-only users continue logging in without ever setting a password.

import { Aside, Steps, Tabs, TabItem } from '@astrojs/starlight/components';

This guide walks through migrating an existing Auth.js (NextAuth.js) application to ideal-auth. The migration can be done incrementally — you can run both libraries side by side during the transition.

---

## Why migrate?

**Auth.js is opinionated about data access.** It requires database adapters (Prisma adapter, Drizzle adapter, etc.) that manage your schema and queries. ideal-auth is bring-your-own — you write the database queries, you control the schema, you decide what ORM to use (or none).

**Auth.js bundles everything.** OAuth providers, email/password, magic links, database sessions, JWT sessions — all in one package. If you only need session auth with email/password, you carry the weight of features you do not use. ideal-auth focuses on session auth primitives and lets you compose other tools (e.g., [Arctic](https://arcticjs.dev) for OAuth).

**Simpler mental model.** Auth.js has providers, callbacks (`signIn`, `jwt`, `session`, `redirect`), adapter interfaces, and strategy-specific configuration. ideal-auth has `createAuth`, `createHash`, and explicit methods like `session.attempt()`, `session.login()`, `session.logout()`. You call what you need, when you need it.

**No magic.** Auth.js injects routes (`/api/auth/*`), manages CSRF tokens internally, and handles redirects behind configuration. ideal-auth does not inject routes, does not manage CSRF (that is framework-level), and does not redirect — you call `redirect()` yourself.

---

## Key differences

| Concept | Auth.js | ideal-auth |
|---------|---------|------------|
| Session storage | Database session or JWT | Encrypted cookie (iron-session) |
| Database access | Adapter pattern (Prisma, Drizzle, etc.) | You write the queries (`resolveUser`, `resolveUserByCredentials`) |
| Password hashing | Not built-in (you handle it in `authorize`) | Built-in (`createHash` with bcrypt + SHA-256 prehash) |
| Login | `signIn("credentials", { ... })` | `session.attempt({ email, password })` |
| Logout | `signOut()` | `session.logout()` |
| Session check | `auth()` or `getSession()` returns session | `session.check()` returns boolean, `session.user()` returns user |
| OAuth | Built-in providers | Not included — use [Arctic](https://arcticjs.dev) |
| CSRF | Built-in (managed internally) | Framework-level (see [CSRF guide](/ideal-auth/security/csrf/)) |
| Route protection | Middleware with `auth()` | Middleware with cookie check + server-side `session.user()` |
| Cookie control | Limited (some options exposed) | Full control via `ConfigurableCookieOptions` (except `httpOnly`, which is forced) |
| 2FA | Not built-in | Built-in (`createTOTP`, `generateRecoveryCodes`) |
| Rate limiting | Not built-in | Built-in (`createRateLimiter`) |
| Token verification | Not built-in | Built-in (`createTokenVerifier`) |

---

## Migration steps

<Steps>

1. ### Install ideal-auth alongside Auth.js

   Keep Auth.js running while you set up ideal-auth. This allows you to migrate incrementally without breaking existing functionality.

   ```bash
   bun add ideal-auth
   ```

2. ### Create the auth configuration

   ```ts title="lib/ideal-auth.ts"
   import { createAuth, createHash } from 'ideal-auth';
   import { cookies } from 'next/headers';
   import { db } from './db';

   type User = {
     id: string;
     email: string;
     name: string;
     password: string;
   };

   export const hash = createHash({ rounds: 12 });

   export const auth = createAuth<User>({
     secret: process.env.IDEAL_AUTH_SECRET!,
     cookie: {
       async get(name) {
         const jar = await cookies();
         return jar.get(name)?.value;
       },
       async set(name, value, options) {
         const jar = await cookies();
         jar.set(name, value, options);
       },
       async delete(name) {
         const jar = await cookies();
         jar.delete(name);
       },
     },
     hash,

     async resolveUser(id) {
       return db.user.findUnique({ where: { id } });
     },

     async resolveUserByCredentials(credentials) {
       return db.user.findUnique({
         where: { email: credentials.email },
       });
     },
   });
   ```

   <Aside>
     If your Auth.js setup uses a different password field name (e.g., `hashedPassword`), set the `passwordField` option in `createAuth`:

     ```ts
     export const auth = createAuth<User>({
       // ...
       passwordField: 'hashedPassword',
     });
     ```
   </Aside>

3. ### Migrate resolveUser to use your existing queries

   If you were using Auth.js with a database adapter, you already have a users table. Point `resolveUser` at it:

   **Prisma example:**
   ```ts
   async resolveUser(id) {
     return db.user.findUnique({ where: { id } });
   },
   ```

   **Drizzle example:**
   ```ts
   async resolveUser(id) {
     const [user] = await db.select().from(users).where(eq(users.id, id));
     return user ?? null;
   },
   ```

   **Raw SQL example:**
   ```ts
   async resolveUser(id) {
     const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [id]);
     return rows[0] ?? null;
   },
   ```

4. ### Replace signIn with session.attempt

   **Before (Auth.js):**
   ```ts
   import { signIn } from 'next-auth/react';

   // Client-side
   await signIn('credentials', {
     email,
     password,
     redirect: false,
   });

   // Or server-side (Auth.js v5)
   import { signIn } from '@/auth';
   await signIn('credentials', { email, password });
   ```

   **After (ideal-auth):**
   ```ts title="app/actions/login.ts"
   'use server';

   import { redirect } from 'next/navigation';
   import { auth } from '@/lib/ideal-auth';

   export async function loginAction(_prev: unknown, formData: FormData) {
     const email = formData.get('email') as string;
     const password = formData.get('password') as string;

     const session = auth();
     const success = await session.attempt({ email, password });

     if (!success) {
       return { error: 'Invalid email or password.' };
     }

     redirect('/dashboard');
   }
   ```

5. ### Replace signOut with session.logout

   **Before (Auth.js):**
   ```ts
   import { signOut } from 'next-auth/react';
   await signOut({ redirect: true, callbackUrl: '/login' });
   ```

   **After (ideal-auth):**
   ```ts title="app/actions/logout.ts"
   'use server';

   import { redirect } from 'next/navigation';
   import { auth } from '@/lib/ideal-auth';

   export async function logoutAction() {
     const session = auth();
     await session.logout();
     redirect('/login');
   }
   ```

6. ### Replace session checks

   **Before (Auth.js):**
   ```ts
   import { auth } from '@/auth';

   // In a Server Component
   const session = await auth();
   if (!session) redirect('/login');
   const user = session.user;
   ```

   **After (ideal-auth):**
   ```ts
   import { auth } from '@/lib/ideal-auth';

   // In a Server Component
   const session = auth();
   const user = await session.user();
   if (!user) redirect('/login');
   ```

   **Before (Auth.js client-side):**
   ```tsx
   import { useSession } from 'next-auth/react';

   function Dashboard() {
     const { data: session, status } = useSession();
     if (status === 'loading') return <p>Loading...</p>;
     if (!session) redirect('/login');
     return <p>Welcome, {session.user.name}</p>;
   }
   ```

   **After (ideal-auth):**

   ideal-auth does not have a client-side session hook. Fetch the user server-side and pass it as props:

   ```tsx title="app/dashboard/page.tsx"
   import { auth } from '@/lib/ideal-auth';
   import { redirect } from 'next/navigation';
   import { DashboardClient } from './dashboard-client';

   export default async function DashboardPage() {
     const session = auth();
     const user = await session.user();
     if (!user) redirect('/login');

     return <DashboardClient user={{ id: user.id, name: user.name, email: user.email }} />;
   }
   ```

7. ### Update middleware

   **Before (Auth.js):**
   ```ts
   export { auth as middleware } from '@/auth';

   export const config = {
     matcher: ['/dashboard/:path*'],
   };
   ```

   **After (ideal-auth):**

   Since ideal-auth uses iron-session (Node.js crypto), you cannot decrypt the session in Edge middleware. Instead, check for the cookie's existence:

   ```ts title="middleware.ts"
   import { NextResponse } from 'next/server';
   import type { NextRequest } from 'next/server';

   export function middleware(request: NextRequest) {
     const hasSession = request.cookies.has('ideal_session');

     if (!hasSession) {
       const loginUrl = new URL('/login', request.url);
       loginUrl.searchParams.set('redirect', request.nextUrl.pathname);
       return NextResponse.redirect(loginUrl);
     }

     return NextResponse.next();
   }

   export const config = {
     matcher: ['/dashboard/:path*', '/settings/:path*'],
   };
   ```

   <Aside type="tip">
     The middleware cookie check is a fast first pass. The actual session is cryptographically verified when `session.user()` or `session.check()` runs server-side. An expired or tampered cookie will fail there.
   </Aside>

8. ### Handle OAuth separately

   ideal-auth does not include OAuth. If your Auth.js setup uses OAuth providers (Google, GitHub, etc.), you have two options:

   **Option A: Keep Auth.js for OAuth only.** Remove the credentials provider from Auth.js and keep it exclusively for OAuth. Use ideal-auth for email/password login. Both can coexist — they use different session cookies.

   **Option B: Switch to Arctic.** [Arctic](https://arcticjs.dev) is a lightweight OAuth 2.0 library that provides provider-specific helpers without the adapter/session layer. You handle the OAuth flow yourself and call `session.login(user)` with ideal-auth after verifying the OAuth token.

   ```ts title="Example: GitHub OAuth with Arctic + ideal-auth"
   import { GitHub } from 'arctic';
   import { auth } from '@/lib/ideal-auth';

   const github = new GitHub(
     process.env.GITHUB_CLIENT_ID!,
     process.env.GITHUB_CLIENT_SECRET!,
     null,
   );

   // After the OAuth callback
   export async function handleGitHubCallback(code: string) {
     const tokens = await github.validateAuthorizationCode(code);
     const githubUser = await fetchGitHubUser(tokens.accessToken());

     // Find or create user in your database
     let user = await db.user.findUnique({
       where: { githubId: githubUser.id },
     });

     if (!user) {
       user = await db.user.create({
         data: {
           email: githubUser.email,
           name: githubUser.name,
           githubId: githubUser.id,
         },
       });
     }

     // Log them in with ideal-auth
     const session = auth();
     await session.login(user);
   }
   ```

9. ### Remove Auth.js

   Once all flows are migrated:

   ```bash
   bun remove next-auth @auth/prisma-adapter  # or your adapter
   ```

   Delete:
   - `auth.ts` or `auth.config.ts` (Auth.js configuration)
   - `app/api/auth/[...nextauth]/route.ts` (Auth.js API route)
   - `SessionProvider` wrapper in your layout (no longer needed)
   - Any `useSession` or `getSession` imports

</Steps>

---

## Code comparison

| Operation | Auth.js | ideal-auth |
|-----------|---------|------------|
| Initialize | `NextAuth({ providers: [...], adapter: ... })` | `createAuth({ secret, cookie, resolveUser, ... })` |
| Login | `signIn("credentials", { email, password })` | `auth().attempt({ email, password })` |
| Logout | `signOut()` | `auth().logout()` |
| Get session | `auth()` / `getSession()` | `auth().check()` (boolean) |
| Get user | `(await auth())?.user` | `await auth().user()` |
| Get user ID | `(await auth())?.user?.id` | `await auth().id()` |
| Login with user object | Not directly available | `auth().login(user)` |
| Hash password | Manual (`bcrypt.hash()`) | `hash.make(password)` |
| Verify password | Manual (`bcrypt.compare()`) | `hash.verify(password, hash)` |

---

## Handling OAuth users without passwords

If you have existing users who signed up via OAuth and have no password in your database, they need a way to authenticate with ideal-auth. Two approaches:

**1. "Set password" flow.** After migration, prompt OAuth users to set a password. Send them to a page where they enter a new password, which you hash and store. They can then log in with email/password.

**2. Keep OAuth separate.** Use Arctic (or keep Auth.js) for OAuth login. After verifying the OAuth token, look up the user and call `session.login(user)` with ideal-auth. The user never needs a password.

<Aside>
  Approach 2 is recommended if you have a significant number of OAuth-only users. Forcing them to set a password is poor user experience.
</Aside>

---

## Password rehashing

If your Auth.js application used a different hashing algorithm (e.g., `argon2` or `scrypt` directly), you need to rehash passwords as users log in:

```ts title="lib/ideal-auth.ts"
export const auth = createAuth<User>({
  // ...

  // Use attemptUser for custom hash migration logic
  async attemptUser(credentials) {
    const { password, ...lookup } = credentials;
    const user = await db.user.findUnique({
      where: { email: lookup.email },
    });
    if (!user || !user.password) return null;

    // Check if the hash is already bcrypt (starts with $2a$ or $2b$)
    if (user.password.startsWith('$2')) {
      // Already bcrypt — use ideal-auth's hash.verify
      const valid = await hash.verify(password, user.password);
      return valid ? user : null;
    }

    // Legacy hash — verify with old algorithm
    const valid = await verifyLegacyHash(password, user.password);
    if (!valid) return null;

    // Rehash with bcrypt for next time
    const newHash = await hash.make(password);
    await db.user.update({
      where: { id: user.id },
      data: { password: newHash },
    });

    return user;
  },
});
```

This transparently migrates password hashes on each login until all users have been rehashed.

